/**
 * @generated by @flusk/cli — middleware recipe
 */

// --- BEGIN GENERATED ---
import { EventEmitter } from 'node:events'
// --- END GENERATED ---

// --- BEGIN CUSTOM ---
export interface CostEvent {
  type: 'call.tracked' | 'cost.update'
  data: {
    id?: string
    provider?: string
    model?: string
    cost?: number
    totalTokens?: number
    timestamp: string
  }
}

/**
 * In-process event bus for real-time cost tracking
 * SSE clients subscribe, LLM call creation emits
 */
class CostEventBus extends EventEmitter {
  override emit(event: 'cost', data: CostEvent): boolean
  override emit(event: string | symbol, ...args: unknown[]): boolean
  override emit(event: string | symbol, ...args: unknown[]): boolean {
    return super.emit(event, ...args)
  }

  override on(event: 'cost', listener: (data: CostEvent) => void): this
  override on(event: string | symbol, listener: (...args: unknown[]) => void): this
  override on(event: string | symbol, listener: (...args: unknown[]) => void): this {
    return super.on(event, listener)
  }

  override off(event: 'cost', listener: (data: CostEvent) => void): this
  override off(event: string | symbol, listener: (...args: unknown[]) => void): this
  override off(event: string | symbol, listener: (...args: unknown[]) => void): this {
    return super.off(event, listener)
  }
}

export const costEventBus = new CostEventBus()
costEventBus.setMaxListeners(100)
// --- END CUSTOM ---
