    const items = BudgetAlertRepository.listBudgetAlerts(fastify.db, limit, offset);
    return reply.code(200).send(items);
  });

  fastify.put('/:id', {
    schema: {
      params: IdParamsSchema,
      body: Type.Partial(CreateBudgetAlertSchema),
      response: { 200: BudgetAlertResponseSchema as TSchema, 404: NotFoundSchema },
